/**
 * 卡片光晕交互模块 - Magical Card Hover Effect
 * 鼠标悬停时径向渐变光晕跟随鼠标位置
 */
window.addEventListener("mousemove",function(e){document.querySelectorAll(".magical").forEach(n=>{n.querySelector(".show")||n.insertAdjacentHTML("beforeend","<div class='show'></div>");const t=n.getBoundingClientRect(),i=e.clientX-t.left,o=e.clientY-t.top;n.style.setProperty("--mouse-x",`${i}px`),n.style.setProperty("--mouse-y",`${o}px`);const l=n.querySelector(".show");l&&(l.style.opacity=i>=0&&i<=n.clientWidth&&o>=0&&o<=n.clientHeight?1:0)})});
